def min_window_subsequence_brute(S, T):
    if not T:
        return ''
    n, m = len(S), len(T)
    min_len = float('inf')
    result = ''
    for i in range(n):
        for j in range(i, n):
            # Check if T is subsequence of S[i:j+1]
            t_idx = 0
            for k in range(i, j+1):
                if S[k] == T[t_idx]:
                    t_idx += 1
                    if t_idx == m:
                        break
            if t_idx == m:  # Found subsequence
                window_len = j - i + 1
                if window_len < min_len:
                    min_len = window_len
                    result = S[i:j+1]
    return result

def is_subsequence_in_window(S, i, j, T):
    if not T:
        return True
    t_idx = 0
    for k in range(i, j+1):
        if S[k] == T[t_idx]:
            t_idx += 1
            if t_idx == len(T):
                return True
    return False

