def compare_sequences(S, T):
    t_idx = 0
    for s in S:
        if t_idx < len(T) and s == T[t_idx]:
            t_idx += 1
    return t_idx == len(T)

def extract_window(S, i, j):
    if i < 0 or j >= len(S) or i > j:
        return ''  # or raise error
    return S[i:j+1]

